ids = B._idgen(550005)
def nid(): return next(ids)
sids = B._idgen(885005)
def sid(): return next(sids)

def act(_id, label): return f"@UUID[Compendium.{MODID}.cotct-actors.Actor.{_id}]{{{label}}}"
def haz(_id, label): return f"@UUID[Compendium.{MODID}.cotct-hazards.Actor.{_id}]{{{label}}}"
def itm(_id, label): return f"@UUID[Compendium.{MODID}.cotct-items.Item.{_id}]{{{label}}}"
def chk(s): return f"@Check[{s}]"
def SEC(html): return B.s_secret(html, sid())
def box(anchor, fb):
    t = B.verbatim(anchor)
    return B.s_read(B.parafy(t)) if t else B.s_read(fb)
def boxcap(anchor, fb):
    """box() for paragraphs whose OCR drop-cap loss left a lowercase opening."""
    t = B.verbatim(anchor)
    if t: t = t[0].upper() + t[1:]
    return B.s_read(B.parafy(t)) if t else B.s_read(fb)
def vsec(anchor, fb):
    """Verbatim GM prose (not read-aloud) into a secret section, with fallback."""
    t = B.verbatim(anchor)
    return SEC(B.parafy(t) if t else fb)
